/**
 * IconFieldEditor — Shared component for PropertyPanels
 * Author: generated by Amazon Q
 * Created: 2025-01-01
 * Purpose: Inline icon editor supporting Emoji + Font Awesome for section PropertyPanels
 */

'use client';

import React, { useState } from 'react';
import { IconConfig, IconDisplay, IconPicker } from '@/components/ui/IconPicker';

interface IconFieldEditorProps {
  /** Current emoji value (e.g. "⚡") */
  emoji?: string;
  /** Current FA icon config */
  faConfig?: IconConfig;
  /** Called when either changes */
  onChange: (emoji: string, faConfig: IconConfig | null) => void;
  label?: string;
}

const inputCls = 'w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 text-gray-900 dark:text-white text-sm';

export function IconFieldEditor({ emoji = '', faConfig, onChange, label = 'Icon' }: IconFieldEditorProps) {
  const [mode, setMode] = useState<'emoji' | 'fa'>(faConfig?.name ? 'fa' : 'emoji');
  const [showPicker, setShowPicker] = useState(false);

  const switchMode = (m: 'emoji' | 'fa') => {
    setMode(m);
    setShowPicker(false);
    if (m === 'emoji') onChange(emoji, null);
    else onChange('', faConfig || null);
  };

  return (
    <div className="space-y-2">
      {label && (
        <label className="block text-xs font-medium text-gray-600 dark:text-gray-400">{label}</label>
      )}

      {/* Toggle */}
      <div className="flex gap-1 p-1 bg-gray-100 dark:bg-gray-700 rounded-lg">
        <button type="button" onClick={() => switchMode('emoji')}
          className={`flex-1 py-1 text-xs rounded-md font-medium transition-colors ${mode === 'emoji' ? 'bg-white dark:bg-gray-600 text-gray-900 dark:text-white shadow-sm' : 'text-gray-500 dark:text-gray-400'}`}>
          😀 Emoji
        </button>
        <button type="button" onClick={() => switchMode('fa')}
          className={`flex-1 py-1 text-xs rounded-md font-medium transition-colors ${mode === 'fa' ? 'bg-white dark:bg-gray-600 text-gray-900 dark:text-white shadow-sm' : 'text-gray-500 dark:text-gray-400'}`}>
          <i className="fas fa-icons mr-1" aria-hidden="true" />FA Icon
        </button>
      </div>

      {/* Emoji input */}
      {mode === 'emoji' && (
        <div className="flex gap-2 items-center">
          <input
            type="text"
            value={emoji}
            onChange={e => onChange(e.target.value, null)}
            placeholder="e.g. ⚡ 📊 🚀"
            className={`flex-1 ${inputCls} text-xl text-center`}
          />
          {emoji && (
            <div className="w-10 h-10 flex items-center justify-center bg-gray-50 dark:bg-gray-700 rounded-lg border border-gray-200 dark:border-gray-600 text-2xl flex-shrink-0">
              {emoji}
            </div>
          )}
        </div>
      )}

      {/* FA picker */}
      {mode === 'fa' && (
        <div className="space-y-1.5">
          <button type="button" onClick={() => setShowPicker(p => !p)}
            className="w-full px-3 py-2.5 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 hover:bg-gray-50 dark:hover:bg-gray-600 transition-colors text-left">
            {faConfig?.name ? (
              <div className="flex items-center gap-3">
                <div className="w-8 h-8 flex items-center justify-center bg-gray-100 dark:bg-gray-600 rounded">
                  <IconDisplay icon={faConfig} />
                </div>
                <div>
                  <div className="text-sm font-medium text-gray-900 dark:text-white">fa-{faConfig.name}</div>
                  <div className="text-xs text-gray-500 dark:text-gray-400">{faConfig.type} · {faConfig.size}</div>
                </div>
                <span className="ml-auto text-xs text-blue-600 dark:text-blue-400">{showPicker ? '▲' : '▼'} Change</span>
              </div>
            ) : (
              <span className="text-sm text-gray-500 dark:text-gray-400">Click to select icon...</span>
            )}
          </button>

          {faConfig?.name && (
            <button type="button" onClick={() => onChange('', null)}
              className="text-xs text-red-500 hover:text-red-700">✕ Clear</button>
          )}

          {showPicker && (
            <div className="relative z-50">
              <IconPicker
                value={faConfig}
                onChange={icon => { onChange('', icon); setShowPicker(false); }}
                onClose={() => setShowPicker(false)}
                className="shadow-2xl"
              />
            </div>
          )}
        </div>
      )}
    </div>
  );
}
